appsmith.onReady(() => {
  renderRiskDelta();
});
appsmith.onModelChange(() => {
  renderRiskDelta();
});
function renderRiskDelta() {
  const data = appsmith.model;
  const current = data.current_metrics || {};
  const baseline = data.baseline_metrics || {};

  // Current Values
  const currViolations = current.data_policy_violation_rate?.violations || 0;
  const currPii = current.count_pii_used?.total_pii || 0;
  const currDisparity = 1.8; // Simulated from Frame 4 outcome metrics
  const currConsumers = 2; // Simulated from Frame 2 context

  // Set UI Current Values
  document.getElementById('current-violations').textContent = currViolations;
  document.getElementById('current-pii').textContent = currPii;
  document.getElementById('current-disparity').textContent = currDisparity.toFixed(2);

  // Helper to calculate and style diffs
  function applyDiff(cardId, badgeId, currentVal, baselineVal, lowerIsBetter = true) {
    // Fix JS floating-point artifact by forcing a 2-decimal round
    const diff = Number((currentVal - baselineVal).toFixed(2));
    const badge = document.getElementById(badgeId);
    const card = document.getElementById(cardId);
    let prefix = diff > 0 ? "+" : "";
    badge.textContent = `${prefix}${diff}`;
    if (diff === 0) {
      badge.className = "delta-diff badge badge-neutral";
      card.className = "delta-card border-neutral";
    } else {
      const isDegradation = lowerIsBetter ? diff > 0 : diff < 0;
      if (isDegradation) {
        badge.className = "delta-diff badge badge-critical";
        card.className = "delta-card border-critical";
      } else {
        badge.className = "delta-diff badge badge-safe";
        card.className = "delta-card border-safe";
      }
    }
    return diff;
  }

  // Apply Diffs
  const diffViolations = applyDiff('card-delta-violations', 'diff-violations', currViolations, baseline.total_violations);
  const diffPii = applyDiff('card-delta-pii', 'diff-pii', currPii, baseline.total_pii);
  const diffDisparity = applyDiff('card-delta-disparity', 'diff-disparity', currDisparity, baseline.disparity_score);
  const diffConsumers = currConsumers - baseline.known_consumers;

  // Generate Top 5 Changes List
  const changes = [];
  if (diffViolations > 0) {
    changes.push(`<strong>Policy Drift:</strong> ${diffViolations} new eligibility violations detected.<br><span class="evidence-pointer">Evidence: New features observed in input schema mapping to restricted variables.</span>`);
  }
  if (diffPii > 0) {
    changes.push(`<strong>Sensitive Inputs:</strong> ${diffPii} new restricted PII fields introduced.<br><span class="evidence-pointer">Evidence: Features 'Gender' and 'Age' detected in model usage.</span>`);
  }
  if (diffDisparity > 0) {
    changes.push(`<strong>Outcome Disparity:</strong> Performance metric disparity increased by ${diffDisparity}.<br><span class="evidence-pointer">Evidence: 'Mean Predicted Tenure' delta for 'Gender: Female' segment expanded vs baseline.</span>`);
  }
  if (diffConsumers > 0) {
    changes.push(`<strong>Runtime Exposure:</strong> ${diffConsumers} new consumer application(s) detected.<br><span class="evidence-pointer">Evidence: 'Manager_Portal' recently added as a caller to /api/v1/predict/retention.</span>`);
  }
  if (changes.length < 5) {
    changes.push(`<strong>Proxy Relationships:</strong> Stable.<br><span class="evidence-pointer">Evidence: No new high-correlation proxy features detected vs baseline.</span>`);
  }

  // Render List
  const listEl = document.getElementById('top-changes-list');
  listEl.innerHTML = "";
  changes.slice(0, 5).forEach(change => {
    const li = document.createElement('li');
    li.innerHTML = change;
    listEl.appendChild(li);
  });

  // Update container border based on worst change
  const container = document.querySelector('.changes-container');
  if (diffViolations > 0 || diffPii > 0 || diffDisparity > 0) {
    container.className = "changes-container border-critical";
  } else if (diffViolations === 0 && diffPii === 0) {
    container.className = "changes-container border-safe";
  }
}

